<script>import{onMount}from'svelte';export let label,side,align,sideOffset=8,alignOffset=0,open=false,closeOnOutside=true,closeOnEscape=true;let shown=open,root,trigger;const id='popover-'+label.toLowerCase().replace(/\W/g,'-');onMount(()=>{const outside=e=>{if(closeOnOutside&&!root.contains(e.target))shown=false},key=e=>{if(e.key==='Escape'&&closeOnEscape){shown=false;trigger.focus()}};document.addEventListener('pointerdown',outside);document.addEventListener('keydown',key);return()=>{document.removeEventListener('pointerdown',outside);document.removeEventListener('keydown',key)}})</script><section bind:this={root} class="popover-demo"><strong>{label}</strong><button bind:this={trigger} class="popover-trigger" aria-haspopup="dialog" aria-expanded={shown} aria-controls={id} onclick={()=>shown=!shown}>Toggle</button>{#if shown}<div {id} role="dialog" aria-label={label} class="kumo-popover side-{side} align-{align}" style="--side-offset:{sideOffset}px;--align-offset:{alignOffset}px"><p>Popover content</p><button onclick={()=>shown=false}>Close</button></div>{/if}</section>